import React, {useCallback, useState} from 'react'
import {useDropzone} from "react-dropzone";
import {formatSize} from "~/lib/utils";

interface FileUploaderProps {
    onFileSelect?: (file: File | null) => void,
}

const FileUploader = ({onFileSelect} : FileUploaderProps) => {
    const [selectedFile, setSelectedFile] = useState<File | null>(null);

    const onDrop = useCallback( (acceptedFiles : File[])  => {
        const file = acceptedFiles[0] || null;
        setSelectedFile(file);
        onFileSelect?.(file);
    }, [onFileSelect]);

    const {getRootProps, getInputProps, isDragActive, acceptedFiles} = useDropzone({
        onDrop,
        multiple: false,
        accept : {'application/pdf': ['.pdf']},
        maxSize: 20 * 1024 * 1024,
    })

    const file = acceptedFiles[0] || null;

    return (

        <div className="w-full gradient-border">
            <div {...getRootProps()} className="space-y-4 cursor-pointer">
                <input {...getInputProps()} />


                {file ?
                    (<div className="uploader-selected-file " onClick={(e) => e.stopPropagation() }>
                            <img src="/images/pdf.png" alt="pdf" className="size-10"/>
                            <div className="flex item-center space-x-3">

                                <p className="text-sm font-medium text-gray-700 truncate max-w-xs">{file.name}</p>
                                <p className="text-sm text-gray-500">{formatSize(file.size)}</p>
                            </div>

                            <button type="button" className="p-2 cursor-pointer" onClick={(e) => {onFileSelect?.(null)}}>
                                <img src="/icons/cross.svg" alt="remove" className="w-4 h-4"/>
                            </button>
                    </div>

                    ) :(
                            <div>
                                <div className="mx-auto w-16 h-16 flex items-center justify-cente mb-6">
                                    <img src = "/icons/info.svg" alt="upload" className="size-20"/>
                                </div>
                                <p className="text-lg text-gray-500">
                                    <span className="font-semibold">Click to upload</span> or drag and drop a
                                </p>
                                    <p className="text-gray-500">PDF (max 20MB)</p>

                            </div>

                    ) }

            </div>

        </div>
    )
}
export default FileUploader

import React, {useCallback, useState} from 'react'
import {useDropzone} from "react-dropzone";
import {formatSize} from "~/lib/utils";

interface FileUploaderProps {
    onFileSelect?: (file: File | null) => void,
}

const FileUploader = ({onFileSelect} : FileUploaderProps) => {
    const [selectedFile, setSelectedFile] = useState<File | null>(null);

    const onDrop = useCallback( (acceptedFiles : File[])  => {
        const file = acceptedFiles[0] || null;
        setSelectedFile(file);
        onFileSelect?.(file);
    }, [onFileSelect]);

    const {getRootProps, getInputProps, isDragActive,acceptedFiles} = useDropzone({
        onDrop,
        multiple: false,
        accept : {'application/pdf': ['.pdf']},
        maxSize: 20 * 1024 * 1024,
    })

    return (

        <div className="w-full gradient-border">
            <div {...getRootProps()} className="space-y-4 cursor-pointer">
                <input {...getInputProps()} />


                {selectedFile ?
                    (<div className="uploader-selected-file " onClick={(e) => e.stopPropagation() }>
                            <img src="/images/pdf.png" alt="pdf" className="size-10"/>
                            <div className="flex item-center space-x-3">

                                <p className="text-sm font-medium text-gray-700 truncate max-w-xs">{selectedFile.name}</p>
                                <p className="text-sm text-gray-500">{formatSize(selectedFile.size)}</p>
                            </div>

                            <button type="button" className="p-2 cursor-pointer" onClick={(e) => { setSelectedFile(null); onFileSelect?.(null); }}>
                                <img src="/icons/cross.svg" alt="remove" className="w-4 h-4"/>
                            </button>
                    </div>

                    ) :(
                            <div>
                                <div className="mx-auto w-16 h-16 flex items-center justify-cente mb-6">
                                    <img src = "/icons/info.svg" alt="upload" className="size-20"/>
                                </div>
                                <p className="text-lg text-gray-500">
                                    <span className="font-semibold">Click to upload</span> or drag and drop a
                                </p>
                                    <p className="text-gray-500">PDF (max 20MB)</p>

                            </div>

                    ) }

            </div>

        </div>
    )
}
export default FileUploader

@import url("https://fonts.googleapis.com/css2?family=Mona+Sans:ital,wght@0,200..900;1,200..900&display=swap");
@import "tailwindcss";
@import "tw-animate-css";

@theme {
  --font-sans: "Mona Sans", ui-sans-serif, system-ui, sans-serif,
  "Apple Color Emoji", "Segoe UI Emoji", "Segoe UI Symbol", "Noto Color Emoji";
  --color-dark-bg: #0f172a;
  --color-dark-card: #1e293b;
  --color-dark-border: #334155;
  --color-light-text: #f1f5f9;
  --color-secondary-text: #cbd5e1;
  --color-accent-blue: #3b82f6;
  --color-accent-light-blue: #60a5fa;

  --color-badge-green: #1e4620;
  --color-badge-red: #4c0e18;
  --color-badge-yellow: #6b3e1d;

  --color-badge-green-text: #86efac;
  --color-badge-red-text: #f87171;
  --color-badge-yellow-text: #fbbf24;
}

html,
body {
  @apply bg-gradient text-light-text;
}

main {
  @apply min-h-screen pt-10;
}
h1 {
  @apply max-sm:text-[3rem] text-6xl text-gradient leading-tight xl:tracking-[-2px] font-semibold;
}

h2 {
  @apply max-sm:text-xl text-3xl text-light-text;
}

label {
  @apply text-secondary-text;
}
input {
  @apply w-full p-4 inset-shadow rounded-2xl focus:outline-none bg-[#1e293b] text-light-text placeholder-gray-500 border border-dark-border focus:border-accent-light-blue;
}

textarea {
  @apply w-full p-4 inset-shadow rounded-2xl focus:outline-none bg-[#1e293b] text-light-text placeholder-gray-500 border border-dark-border focus:border-accent-light-blue;
}

form {
  @apply flex flex-col items-start gap-8 w-full;
}

@layer components {
  .text-gradient {
    @apply bg-clip-text text-transparent bg-gradient-to-r from-[#60a5fa] via-[#a78bfa] to-[#f472b6];
  }
  .gradient-border {
    @apply bg-gradient-to-br from-[#1e3a8a] to-[#1e293b] p-4 rounded-2xl border border-dark-border;
  }
  .primary-button {
    @apply primary-gradient text-white rounded-full px-4 py-2 cursor-pointer w-full hover:primary-gradient-hover transition-all;
  }
  .resume-nav {
    @apply flex flex-row justify-between items-center p-4 border-b border-dark-border bg-[#1a1f35]/50 backdrop-blur;
  }
  .resume-summary {
    @apply flex flex-row items-center justify-center p-4 gap-4;
    .category {
      @apply flex flex-row gap-2 items-center bg-[#1e293b]/60 rounded-2xl p-4 w-full justify-between border border-dark-border hover:border-accent-light-blue transition-all;
    }
  }
  .back-button {
    @apply flex flex-row items-center gap-2 border border-dark-border rounded-lg p-2 shadow-sm bg-[#1e293b]/50 text-light-text hover:border-accent-light-blue transition-all cursor-pointer;
  }
  .auth-button {
    @apply primary-gradient rounded-full py-4 px-8 cursor-pointer w-[600px] max-md:w-full text-3xl font-semibold text-white hover:primary-gradient-hover transition-all;
  }
  .main-section {
    @apply flex flex-col items-center gap-8 pt-12 max-sm:mx-2 mx-15 pb-5;
  }
  .page-heading {
    @apply flex flex-col items-center gap-8 max-w-4xl text-center max-sm:gap-4 text-light-text;
  }
  .resumes-section {
    @apply flex flex-wrap max-md:flex-col max-md:gap-4 gap-6 items-start max-md:items-center w-full max-w-[1850px] justify-evenly;
  }

  .resume-card {
    @apply flex flex-col gap-8 h-[560px] w-[350px] lg:w-[430px] xl:w-[490px] bg-[#1e293b] rounded-2xl p-4 border border-dark-border hover:border-accent-light-blue shadow-lg hover:shadow-xl transition-all hover:shadow-accent-blue/20;
  }

  .resume-card-header {
    @apply flex flex-row gap-2 justify-between min-h-[110px] max-sm:flex-col items-center max-md:justify-center max-md:items-center;
  }

  .feedback-section {
    @apply flex flex-col gap-8 w-1/2 px-8 max-lg:w-full py-6 text-light-text;
  }

  .navbar {
    @apply flex flex-row justify-between items-center bg-[#1e293b]/80 backdrop-blur-md rounded-full p-4 w-full px-10 max-w-[1200px] mx-auto border border-dark-border;
  }

  .score-badge {
    @apply flex flex-row items-center justify-center py-1 px-2 gap-4 rounded-[96px] bg-[#1e293b] border border-dark-border;
  }

  .form-div {
    @apply flex flex-col gap-2 w-full items-start text-light-text;
  }

  .uplader-drag-area {
    @apply relative p-8 text-center transition-all duration-700 cursor-pointer bg-[#1e293b] rounded-2xl min-h-[208px] border-2 border-dashed border-dark-border hover:border-accent-light-blue text-secondary-text hover:text-light-text;
  }
  .uploader-selected-file {
    @apply flex items-center justify-between p-3 bg-[#0f172a]/50 rounded-2xl border border-dark-border text-light-text;
  }
}

@utility bg-gradient {
  background: linear-gradient(135deg, #0f172a 0%, #1e293b 50%, #1a1a2e 100%);
}

@utility text-gradient {
  @apply bg-clip-text text-transparent bg-gradient-to-r from-[#60a5fa] via-[#a78bfa] to-[#f472b6];
}

@utility gradient-hover {
  @apply bg-gradient-to-br from-[#1e3a8a]/80 to-[#0f172a]/80;
}

@utility primary-gradient {
  background: linear-gradient(135deg, #3b82f6 0%, #2563eb 50%, #1d4ed8 100%);
  box-shadow: 0px 20px 25px -5px rgba(59, 130, 246, 0.3);
  transition: all 0.3s ease;
}

@utility primary-gradient-hover {
  background: linear-gradient(135deg, #60a5fa 0%, #3b82f6 50%, #2563eb 100%);
  box-shadow: 0px 25px 30px -5px rgba(59, 130, 246, 0.5);
}

@utility inset-shadow {
  box-shadow: inset 0 0 20px 0 rgba(59, 130, 246, 0.15),
              0 0 20px 0 rgba(59, 130, 246, 0.05);
  backdrop-filter: blur(10px);
}

@keyframes fadeIn {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

